const b       = $json.body;
const product = b.productName     || 'Product';
const dur     = parseInt(b.duration || 15);
const style   = b.style           || 'premium product reveal';
const imgUrl  = b.productImageUrl || '';
const jobId   = `ECOM-${Date.now()}`;
const prompt  = `Cinematic ${dur}-second product video for ${product}. ` +
  `Style: ${style}. Start with a dramatic reveal from black, ` +
  `smoothly rotate the product 360 degrees under professional studio lighting, ` +
  `close-up on key features with shallow depth of field, ` +
  `end with the product centred on a clean white background. ` +
  `4K quality, no text, premium commercial aesthetic.`;
return [{ json: { prompt, product, duration: dur, style, productImageUrl: imgUrl, jobId } }];

const prev = $('Build E-commerce Prompt').item.json;
const genId = $json.id || $json.generation_id;
if (!genId) throw new Error('No generation_id returned from Sora');
return [{ json: { ...prev, generationId: genId } }];

const p = $('Build E-commerce Prompt').item.json;
return [{ json: {
  success: true, jobId: p.jobId, jobType: 'ecommerce',
  productName: p.product, duration: p.duration, style: p.style,
  publicUrl: `https://YOUR_CDN_DOMAIN/${p.jobId}.mp4`,
  generatedAt: new Date().toISOString(),
  note: 'Embed this MP4 URL directly in your Shopify/Meesho product listing.'
}}];

const b        = $json.body;
const style    = b.remixStyle     || 'cyberpunk';
const effect   = b.addEffect      || 'golden hour lighting';
const platform = (b.platform || 'reels').toLowerCase();
const srcImg   = b.sourceImageUrl || '';
const jobId    = `REMIX-${Date.now()}`;
const aspect   = ['reels','tiktok','story'].includes(platform) ? '9:16' : '1:1';
const dur      = 8;
const prompt   = `Transform this image into a ${dur}-second cinematic ${style} style video. ` +
  `Apply ${effect} with smooth cinematic camera movement and dramatic transitions. ` +
  `Vibrant colour grading, professional motion blur on cuts, ` +
  `optimised for ${platform} vertical short-form format. No text overlays.`;
return [{ json: { prompt, style, effect, platform, aspect, duration: dur, sourceImageUrl: srcImg, jobId } }];

const prev = $('Build Remix Prompt').item.json;
const genId = $json.id || $json.generation_id;
if (!genId) throw new Error('No generation_id returned from Sora');
return [{ json: { ...prev, generationId: genId } }];

const p = $('Build Remix Prompt').item.json;
return [{ json: {
  success: true, jobId: p.jobId, jobType: 'remix',
  remixStyle: p.style, effect: p.effect,
  platform: p.platform, aspectRatio: p.aspect,
  publicUrl: `https://YOUR_CDN_DOMAIN/${p.jobId}.mp4`,
  generatedAt: new Date().toISOString(),
  note: 'Post this URL directly to TikTok/Reels via their upload API.'
}}];
